"use client";

import { createContext, useContext } from "react";

type CreatorContextValue = {
  email: string | null;
};

const CreatorContext = createContext<CreatorContextValue>({ email: null });

export function CreatorProvider({
  email,
  children
}: {
  email: string | null;
  children: React.ReactNode;
}) {
  return <CreatorContext.Provider value={{ email }}>{children}</CreatorContext.Provider>;
}

export function useCreatorEmail() {
  return useContext(CreatorContext).email;
}

"use client";

import { BookOpen, ClipboardList, LayoutGrid } from "lucide-react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { AppBrandLink } from "@/components/auth/AppBrandLink";
import { LogoutButton } from "@/components/layout/LogoutButton";
import { cn } from "@/lib/utils";

function initialsFromEmail(email: string | null): string {
  if (!email) {
    return "…";
  }
  const local = email.split("@")[0] ?? "";
  const parts = local.split(/[._-]+/).filter(Boolean);
  if (parts.length >= 2) {
    return (parts[0]!.slice(0, 1) + parts[1]!.slice(0, 1)).toUpperCase();
  }
  const compact = local.replace(/[^a-zA-Z0-9]/g, "");
  if (compact.length >= 2) {
    return compact.slice(0, 2).toUpperCase();
  }
  return (local.slice(0, 2) || "?").toUpperCase();
}

const nav = [
  { href: "/programs", label: "Programs", icon: LayoutGrid },
  { href: "/import", label: "Import", icon: ClipboardList },
  { href: "/audit", label: "Audit log", icon: BookOpen }
] as const;

export function AppSidebar({ email }: { email: string | null }) {
  const pathname = usePathname();

  function isActive(href: (typeof nav)[number]["href"]): boolean {
    if (href === "/programs") {
      return pathname === "/programs" || pathname.startsWith("/programs/");
    }
    return pathname === href || pathname.startsWith(`${href}/`);
  }

  return (
    <aside className="flex w-60 shrink-0 flex-col border-r border-border bg-card">
      <div className="p-6">
        <AppBrandLink className="block text-xs font-semibold tracking-[0.2em] text-foreground" />
      </div>

      <div className="mx-5 mb-6 flex gap-3 rounded-xl border border-border/80 bg-muted/30 px-3 py-3">
        <div
          className="flex size-11 shrink-0 items-center justify-center rounded-full bg-accent text-sm font-semibold text-accent-foreground"
          aria-hidden
        >
          {initialsFromEmail(email)}
        </div>
        <div className="min-w-0 flex-1">
          <p className="truncate text-sm font-semibold text-foreground">
            {email ? email.split("@")[0]?.replace(/[._]/g, " ") ?? email : "—"}
          </p>
          <p className="text-xs text-muted-foreground">Creator</p>
        </div>
      </div>

      <nav className="flex flex-1 flex-col gap-0.5 px-3" aria-label="Main">
        {nav.map(({ href, label, icon: Icon }) => {
          const active = isActive(href);
          return (
            <Link
              key={href}
              href={href}
              className={cn(
                "flex items-center gap-3 rounded-lg px-3 py-2.5 text-sm font-medium transition-colors",
                active
                  ? "bg-accent text-accent-foreground"
                  : "text-muted-foreground hover:bg-muted/80 hover:text-foreground"
              )}
            >
              <Icon className="size-4 shrink-0 opacity-80" aria-hidden />
              {label}
            </Link>
          );
        })}
      </nav>

      <div className="mt-auto border-t border-border p-4">
        <LogoutButton className="w-full" />
      </div>
    </aside>
  );
}

"use client";

import { useEffect, useState } from "react";
import { apiFetch } from "@/lib/api";
import { AppSidebar } from "@/components/layout/AppSidebar";
import { CreatorProvider } from "@/components/layout/creatorContext";

export function DashboardShell({ children }: { children: React.ReactNode }) {
  const [email, setEmail] = useState<string | null>(null);

  useEffect(() => {
    let cancelled = false;
    void (async () => {
      const res = await apiFetch("/auth/me");
      const body = await res.json().catch(() => ({}));
      if (cancelled || !res.ok) {
        return;
      }
      const data = body as { data?: { email?: string } };
      const em = typeof data.data?.email === "string" ? data.data.email : null;
      if (!cancelled) {
        setEmail(em);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, []);

  return (
    <CreatorProvider email={email}>
      <div className="flex min-h-screen bg-muted/40">
        <AppSidebar email={email} />
        <div className="min-w-0 flex-1 overflow-auto">{children}</div>
      </div>
    </CreatorProvider>
  );
}

