"use client";

import { Loader2 } from "lucide-react";
import Link from "next/link";
import { useRouter, useSearchParams } from "next/navigation";
import { Suspense, useEffect, useMemo, useState } from "react";
import { useCreatorEmail } from "@/components/layout/creatorContext";
import { ConfirmDialog } from "@/components/ui/ConfirmDialog";
import { buttonVariants } from "@/components/ui/Button";
import { apiFetch, readApiErrorMessage } from "@/lib/api";
import { formatProgramCreatedAt, formatRelativeShort } from "@/lib/formatDisplay";
import { cn } from "@/lib/utils";
import type { Program } from "@/types";

function greetingNameFromEmail(email: string | null): string {
  if (!email) {
    return "";
  }
  const local = email.split("@")[0] ?? "";
  const first = local.split(/[._-]/).filter(Boolean)[0] ?? local;
  if (!first) {
    return "";
  }
  return first.charAt(0).toUpperCase() + first.slice(1).toLowerCase();
}

function ProgramsFallback() {
  return (
    <div className="flex flex-col items-center justify-center gap-3 py-20">
      <Loader2 className="size-8 animate-spin text-muted-foreground" aria-hidden />
      <p className="text-sm text-muted-foreground">Loading programs…</p>
    </div>
  );
}

function ProgramsInner() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const creatorEmail = useCreatorEmail();
  const [programs, setPrograms] = useState<Program[] | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [banner, setBanner] = useState<string | null>(null);
  const [deleteTarget, setDeleteTarget] = useState<Program | null>(null);
  const [deleteError, setDeleteError] = useState<string | null>(null);

  const greeting = greetingNameFromEmail(creatorEmail);

  const stats = useMemo(() => {
    if (!programs?.length) {
      return {
        totalPrograms: 0,
        totalSessions: 0,
        lastActivity: null as string | null
      };
    }
    const totalSessions = programs.reduce((sum, p) => sum + (p.sessionCount ?? 0), 0);
    const latest = programs.reduce((best, p) => {
      const t = new Date(p.createdAt).getTime();
      if (Number.isNaN(t)) {
        return best;
      }
      if (!best || t > new Date(best).getTime()) {
        return p.createdAt;
      }
      return best;
    }, null as string | null);
    return {
      totalPrograms: programs.length,
      totalSessions,
      lastActivity: latest
    };
  }, [programs]);

  useEffect(() => {
    const created = searchParams.get("created");
    const saved = searchParams.get("saved");
    if (created) {
      setBanner("Program created.");
    } else if (saved) {
      setBanner("Changes saved.");
    }
    if (created || saved) {
      router.replace("/programs", { scroll: false });
    }
  }, [searchParams, router]);

  useEffect(() => {
    if (!banner) {
      return;
    }
    const t = window.setTimeout(() => setBanner(null), 5000);
    return () => window.clearTimeout(t);
  }, [banner]);

  useEffect(() => {
    let cancelled = false;
    void (async () => {
      const res = await apiFetch("/programs");
      const body = await res.json().catch(() => ({}));
      if (cancelled) {
        return;
      }
      if (!res.ok) {
        setError(readApiErrorMessage(body, "Failed to load programs"));
        return;
      }
      const data = body as { programs?: Program[] };
      const rows = (data.programs ?? []).map((p) => ({
        ...p,
        sessionCount: typeof p.sessionCount === "number" ? p.sessionCount : 0,
        createdAt: p.createdAt ?? ""
      }));
      setPrograms(rows);
    })();
    return () => {
      cancelled = true;
    };
  }, []);

  async function onConfirmDeleteProgram() {
    if (!deleteTarget) {
      return;
    }
    setDeleteError(null);
    const res = await apiFetch(`/programs/${deleteTarget.id}`, { method: "DELETE" });
    if (!res.ok) {
      const body = await res.json().catch(() => ({}));
      setDeleteError(readApiErrorMessage(body, "Delete failed"));
      throw new Error("delete failed");
    }
    setPrograms((prev) => (prev ? prev.filter((p) => p.id !== deleteTarget.id) : prev));
  }

  if (error) {
    return <p className="text-sm text-red-600">{error}</p>;
  }
  if (!programs) {
    return <ProgramsFallback />;
  }

  const lastActivityLabel =
    stats.lastActivity != null ? formatRelativeShort(stats.lastActivity) : "—";

  return (
    <div className="space-y-8">
      {banner ? (
        <div
          className="rounded-lg border border-green-200 bg-green-50 px-4 py-3 text-sm text-green-900 dark:border-green-900 dark:bg-green-950/40 dark:text-green-100"
          role="status"
        >
          {banner}
        </div>
      ) : null}

      <header className="space-y-1">
        <h1 className="text-2xl font-semibold tracking-tight text-foreground md:text-3xl">
          Welcome back{greeting ? `, ${greeting}` : ""}.
        </h1>
        <p className="text-sm text-muted-foreground md:text-base">
          Here&apos;s what&apos;s happening across your programs today.
        </p>
      </header>

      <section aria-label="Summary" className="grid gap-4 sm:grid-cols-3">
        <div className="rounded-xl border border-border bg-card px-5 py-4 shadow-sm">
          <p className="text-xs font-medium tracking-wide text-muted-foreground uppercase">
            Total programs
          </p>
          <p className="mt-2 text-3xl font-semibold tabular-nums text-foreground">
            {stats.totalPrograms}
          </p>
        </div>
        <div className="rounded-xl border border-border bg-card px-5 py-4 shadow-sm">
          <p className="text-xs font-medium tracking-wide text-muted-foreground uppercase">
            Total sessions
          </p>
          <p className="mt-2 text-3xl font-semibold tabular-nums text-foreground">
            {stats.totalSessions}
          </p>
        </div>
        <div className="rounded-xl border border-border bg-card px-5 py-4 shadow-sm">
          <p className="text-xs font-medium tracking-wide text-muted-foreground uppercase">
            Last activity
          </p>
          <p className="mt-2 text-2xl font-semibold text-foreground">{lastActivityLabel}</p>
        </div>
      </section>

      {programs.length === 0 ? (
        <div className="rounded-xl border border-dashed border-border bg-card px-6 py-14 text-center">
          <p className="text-muted-foreground">No programs yet. Create your first program.</p>
          <Link href="/programs/new" className={cn(buttonVariants(), "mt-4 inline-flex")}>
            Create your first program
          </Link>
        </div>
      ) : (
        <section
          className="overflow-hidden rounded-xl border border-border bg-card shadow-sm"
          aria-labelledby="your-programs-heading"
        >
          <div className="flex flex-wrap items-center justify-between gap-3 border-b border-border px-5 py-4">
            <h2 id="your-programs-heading" className="text-lg font-semibold text-foreground">
              Your programs
            </h2>
            <div className="flex flex-wrap items-center gap-3">
              <Link
                href="/programs"
                className="text-sm font-medium text-muted-foreground underline-offset-4 hover:text-foreground hover:underline"
              >
                View all →
              </Link>
              <Link href="/programs/new" className={cn(buttonVariants({ size: "sm" }))}>
                New program
              </Link>
            </div>
          </div>
          <ul className="divide-y divide-border">
            {programs.map((p) => {
              const created = formatProgramCreatedAt(p.createdAt);
              const count = p.sessionCount;
              const countLabel = `${count} session${count === 1 ? "" : "s"}`;
              const sessionsHref = `/programs/${p.id}/sessions`;
              return (
                <li key={p.id} className="flex flex-wrap items-center gap-3 px-5 py-4">
                  <div className="min-w-0 flex-1 space-y-1">
                    <p className="font-semibold text-foreground">{p.title}</p>
                    <p className="text-sm text-muted-foreground">
                      {created ? `${created} · ` : null}
                      {countLabel}
                    </p>
                    {p.description ? (
                      <p className="text-sm text-muted-foreground line-clamp-2">{p.description}</p>
                    ) : null}
                  </div>
                  <div className="flex shrink-0 flex-wrap items-center justify-end gap-2">
                    <Link
                      href={sessionsHref}
                      className="text-sm font-medium text-primary underline-offset-4 hover:underline"
                    >
                      View →
                    </Link>
                    <Link
                      href={`/programs/${p.id}/edit`}
                      className={cn(buttonVariants({ variant: "secondary", size: "sm" }))}
                    >
                      Edit
                    </Link>
                    <button
                      type="button"
                      className={cn(buttonVariants({ variant: "destructive", size: "sm" }))}
                      onClick={() => setDeleteTarget(p)}
                    >
                      Delete
                    </button>
                  </div>
                </li>
              );
            })}
          </ul>
        </section>
      )}

      <ConfirmDialog
        open={Boolean(deleteTarget)}
        onOpenChange={(open) => {
          if (!open) {
            setDeleteTarget(null);
            setDeleteError(null);
          }
        }}
        title="Delete program?"
        description={
          deleteTarget
            ? `This will permanently delete “${deleteTarget.title}” and all its sessions.`
            : undefined
        }
        confirmLabel="Delete"
        cancelLabel="Cancel"
        confirmVariant="destructive"
        onConfirm={onConfirmDeleteProgram}
      />
      {deleteError ? <p className="text-sm text-red-600">{deleteError}</p> : null}
    </div>
  );
}

export default function ProgramsPage() {
  return (
    <Suspense fallback={<ProgramsFallback />}>
      <ProgramsInner />
    </Suspense>
  );
}

"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { AppBrandLink } from "@/components/auth/AppBrandLink";

function FooterForPath(pathname: string) {
  if (pathname === "/login" || pathname === "/login/") {
    return (
      <p className="text-center text-sm text-muted-foreground">
        New creator?{" "}
        <Link
          href="/signup"
          className="font-semibold text-foreground underline-offset-4 hover:underline"
        >
          Create your account →
        </Link>
      </p>
    );
  }
  if (pathname === "/signup" || pathname === "/signup/") {
    return (
      <p className="text-center text-sm text-muted-foreground">
        Already have an account?{" "}
        <Link
          href="/login"
          className="font-semibold text-foreground underline-offset-4 hover:underline"
        >
          Sign in →
        </Link>
      </p>
    );
  }
  if (pathname === "/forgot-password" || pathname === "/forgot-password/") {
    return (
      <p className="text-center text-sm text-muted-foreground">
        <Link href="/login" className="font-semibold text-foreground underline-offset-4 hover:underline">
          Back to sign in →
        </Link>
      </p>
    );
  }
  if (pathname === "/reset-password" || pathname === "/reset-password/") {
    return (
      <nav aria-label="Account recovery" className="text-center text-sm text-muted-foreground">
        <Link href="/forgot-password" className="underline-offset-4 hover:text-foreground hover:underline">
          Request a new reset link
        </Link>
        <span className="mx-2 text-border" aria-hidden>
          ·
        </span>
        <Link href="/login" className="underline-offset-4 hover:text-foreground hover:underline">
          Back to sign in
        </Link>
      </nav>
    );
  }
  return null;
}

export function AuthChrome({ children }: { children: React.ReactNode }) {
  const pathname = usePathname();
  const footer = FooterForPath(pathname);

  return (
    <div className="flex min-h-screen flex-col bg-muted/35">
      <div className="flex flex-1 flex-col px-4 pb-8 pt-12 sm:px-6 sm:pt-16">
        <div className="mx-auto w-full max-w-md shrink-0 text-center">
          <AppBrandLink className="inline-flex text-xs font-semibold tracking-[0.22em]" />
        </div>
        <main className="mx-auto mt-10 w-full max-w-md rounded-xl border border-border bg-card px-8 py-8">
          {children}
        </main>
        {footer ? <div className="mx-auto mt-8 w-full max-w-md">{footer}</div> : null}
      </div>
      <footer className="py-6 text-center text-xs text-muted-foreground">© 2026 Wellspring</footer>
    </div>
  );
}

