    <RedirectIfAuthed>
      <Suspense
        fallback={
          <div className="flex min-h-[120px] items-center justify-center text-sm text-muted-foreground">
            Loading…
          </div>
        }
      >
        <LoginForm />
      </Suspense>
    </RedirectIfAuthed>
  );
}

