import Link from "next/link";
import { useParams } from "next/navigation";
import { useEffect, useState } from "react";
import { Loader2 } from "lucide-react";
import { SessionList } from "@/components/sessions/SessionList";
import { buttonVariants } from "@/components/ui/Button";
import { apiFetch, readApiErrorMessage } from "@/lib/api";
import {
  DASH_PAGE_MAX,
  dashBackLink,
  dashPageDescription,
  dashPageTitle,
  dashSectionCard
} from "@/lib/dashboardUi";
import { cn } from "@/lib/utils";
import type { Program, SessionRow } from "@/types";

export default function SessionsPage() {
  const params = useParams();
  const programId = typeof params.id === "string" ? params.id : "";
  const [program, setProgram] = useState<Program | null>(null);
  const [sessions, setSessions] = useState<SessionRow[] | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (!programId) {
      return;
    }

    let cancelled = false;
    void (async () => {
      const [progRes, sessRes] = await Promise.all([
        apiFetch(`/programs/${programId}`),
        apiFetch(`/sessions?programId=${encodeURIComponent(programId)}`)
      ]);
      const progBody = await progRes.json().catch(() => ({}));
      const sessBody = await sessRes.json().catch(() => ({}));
      if (cancelled) {
        return;
      }
      if (!progRes.ok) {
        setError(readApiErrorMessage(progBody, "Failed to load program"));
        return;
      }
      if (!sessRes.ok) {
        setError(readApiErrorMessage(sessBody, "Failed to load sessions"));
        return;
      }
      const p = progBody as Program & { sessionCount?: number; createdAt?: string };
      setProgram({
        id: p.id,
        title: p.title,
        description: p.description ?? null,
        createdAt: typeof p.createdAt === "string" ? p.createdAt : "",
        sessionCount: typeof p.sessionCount === "number" ? p.sessionCount : 0
      });
      const s = sessBody as { sessions?: SessionRow[] };
      setSessions(s.sessions ?? []);
    })();

    return () => {
      cancelled = true;
    };
  }, [programId]);

  if (error) {
    return <p className="text-sm text-destructive">{error}</p>;
  }
  if (!sessions || !program) {
    return (
      <div className={cn(DASH_PAGE_MAX, "flex flex-col items-center justify-center gap-3 py-24")}>
        <Loader2 className="size-8 animate-spin text-muted-foreground" aria-hidden />
        <p className="text-sm text-muted-foreground">Loading sessions…</p>
      </div>
    );
  }

  const count = sessions.length;

  return (
    <div className={cn(DASH_PAGE_MAX, "space-y-8")}>
      <div>
        <Link href="/programs" className={dashBackLink}>
          ← Back to programs
        </Link>
        <div className="mt-6 flex flex-wrap items-start justify-between gap-4">
          <div className="min-w-0 space-y-1">
            <h1 className={dashPageTitle}>{program.title}</h1>
            <p className={dashPageDescription}>
              {count} session{count === 1 ? "" : "s"}
              {program.description ? ` · ${program.description}` : null}
            </p>
          </div>
          <div className="flex shrink-0 flex-wrap gap-2">
            <Link href={`/programs/${programId}/sessions/new`} className={cn(buttonVariants({ size: "sm" }))}>
              New session
            </Link>
            <Link
              href={`/programs/${programId}/edit`}
              className={cn(buttonVariants({ variant: "outline", size: "sm" }))}
            >
              Edit program
            </Link>
          </div>
        </div>
      </div>

      <p className="text-xs uppercase tracking-[0.08em] text-muted-foreground">
        Drag handles to reorder · order saves automatically
      </p>

      {sessions.length === 0 ? (
        <div
          className={cn(
            dashSectionCard,
            "border-dashed bg-muted/15 px-8 py-14 text-center text-muted-foreground"
          )}
        >
          <p>No sessions yet. Add your first session.</p>
          <Link href={`/programs/${programId}/sessions/new`} className={cn(buttonVariants(), "mt-5 inline-flex")}>
            New session
          </Link>
        </div>
      ) : (
        <SessionList programId={programId} initialSessions={sessions} />
      )}
    </div>
  );
}

"use client";

import {
  DndContext,
  KeyboardSensor,
  PointerSensor,
  closestCenter,
  useSensor,
  useSensors,
  type DragEndEvent
} from "@dnd-kit/core";
import {
  SortableContext,
  arrayMove,
  sortableKeyboardCoordinates,
  useSortable,
  verticalListSortingStrategy
} from "@dnd-kit/sortable";
import { CSS } from "@dnd-kit/utilities";
import { ArrowRight, GripVertical } from "lucide-react";
import Link from "next/link";
import { useEffect, useState } from "react";
import { ConfirmDialog } from "@/components/ui/ConfirmDialog";
import { buttonVariants } from "@/components/ui/Button";
import { apiFetch, readApiErrorMessage } from "@/lib/api";
import { dashPrimaryLink, dashSectionCard } from "@/lib/dashboardUi";
import { formatSessionDuration } from "@/lib/formatDisplay";
import { cn } from "@/lib/utils";
import type { SessionRow } from "@/types";

export type { SessionRow };

function SortableRow({
  session,
  programId,
  indexDisplay,
  onRequestDelete,
  isFirst
}: {
  session: SessionRow;
  programId: string;
  indexDisplay: number;
  onRequestDelete: (s: SessionRow) => void;
  isFirst: boolean;
}) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: session.id
  });
  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.92 : 1,
    zIndex: isDragging ? 1 : 0
  };

  const firstTag = session.tags?.[0];
  const meta = [session.instructorName, formatSessionDuration(session.durationSeconds), firstTag]
    .filter(Boolean)
    .join(" · ");

  const viewHref = `/programs/${programId}/sessions/${session.id}`;

  return (
    <li
      ref={setNodeRef}
      style={style}
      className={cn(
        "flex flex-wrap items-center justify-between gap-3 px-6 py-4 transition-shadow",
        !isFirst && "border-t border-border"
      )}
    >
      <div className="flex min-w-0 flex-1 items-start gap-2 sm:gap-3">
        <button
          type="button"
          className="mt-0.5 shrink-0 cursor-grab touch-none rounded-md p-1 text-muted-foreground transition-colors hover:bg-muted hover:text-foreground active:cursor-grabbing"
          aria-label="Drag to reorder"
          {...attributes}
          {...listeners}
        >
          <GripVertical className="size-4" aria-hidden />
        </button>
        <div className="min-w-0 flex-1">
          <p className="text-sm font-medium text-foreground">
            <span className="tabular-nums text-muted-foreground">{indexDisplay}.</span>{" "}
            {session.title}
          </p>
          <p className="mt-0.5 text-xs text-muted-foreground">{meta}</p>
        </div>
      </div>
      <div className="flex shrink-0 flex-wrap items-center justify-end gap-2 pl-9 sm:pl-0">
        <Link href={viewHref} className={cn(dashPrimaryLink, "inline-flex items-center gap-1")}>
          View
          <ArrowRight className="size-3.5" aria-hidden />
        </Link>
        <Link
          href={`/programs/${programId}/sessions/${session.id}/edit`}
          className={cn(buttonVariants({ variant: "secondary", size: "sm" }))}
        >
          Edit
        </Link>
        <button
          type="button"
          className={cn(buttonVariants({ variant: "destructive", size: "sm" }))}
          onClick={() => onRequestDelete(session)}
        >
          Delete
        </button>
      </div>
    </li>
  );
}

/** Session list with drag-and-drop reorder and persistence. */
export function SessionList({
  programId,
  initialSessions
}: {
  programId: string;
  initialSessions: SessionRow[];
}) {
  const [items, setItems] = useState<SessionRow[]>(initialSessions);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [deleteTarget, setDeleteTarget] = useState<SessionRow | null>(null);
  const [deleteError, setDeleteError] = useState<string | null>(null);

  useEffect(() => {
    setItems(initialSessions);
  }, [initialSessions]);

  const sensors = useSensors(
    useSensor(PointerSensor, { activationConstraint: { distance: 6 } }),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates })
  );

  async function persistOrder(nextIds: string[]): Promise<boolean> {
    setSaving(true);
    setError(null);
    const res = await apiFetch("/sessions/reorder", {
      method: "POST",
      body: JSON.stringify({
        programId,
        orderedSessionIds: nextIds
      })
    });
    const body = await res.json().catch(() => ({}));
    setSaving(false);
    if (!res.ok) {
      setError(readApiErrorMessage(body, "Reorder failed"));
      return false;
    }
    const data = body as { sessions?: SessionRow[] };
    if (data.sessions) {
      setItems(data.sessions);
    }
    return true;
  }

  function onDragEnd(ev: DragEndEvent) {
    const { active, over } = ev;
    if (!over || active.id === over.id) {
      return;
    }
    const oldIndex = items.findIndex((s) => s.id === active.id);
    const newIndex = items.findIndex((s) => s.id === over.id);
    if (oldIndex < 0 || newIndex < 0) {
      return;
    }
    const previous = items;
    const reordered = arrayMove(items, oldIndex, newIndex);
    setItems(reordered);
    void (async () => {
      const ok = await persistOrder(reordered.map((s) => s.id));
      if (!ok) {
        setItems(previous);
      }
    })();
  }

  async function onConfirmDeleteSession() {
    if (!deleteTarget) {
      return;
    }
    setDeleteError(null);
    const res = await apiFetch(`/sessions/${deleteTarget.id}`, { method: "DELETE" });
    if (!res.ok) {
      const body = await res.json().catch(() => ({}));
      setDeleteError(readApiErrorMessage(body, "Delete failed"));
      throw new Error("delete failed");
    }
    setItems((prev) => prev.filter((s) => s.id !== deleteTarget.id));
  }

  return (
    <div className="space-y-3">
      {(error ?? saving) ? (
        <div className="flex flex-wrap items-center gap-x-3 gap-y-1 text-sm">
          {error ? <p className="text-destructive">{error}</p> : null}
          {saving ? <p className="text-xs text-muted-foreground">Saving order…</p> : null}
        </div>
      ) : null}
      <div className={cn(dashSectionCard, "overflow-hidden")}>
        <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={onDragEnd}>
          <SortableContext items={items.map((s) => s.id)} strategy={verticalListSortingStrategy}>
            <ul>
              {items.map((s, idx) => (
                <SortableRow
                  key={s.id}
                  session={s}
                  programId={programId}
                  indexDisplay={idx + 1}
                  isFirst={idx === 0}
                  onRequestDelete={setDeleteTarget}
                />
              ))}
            </ul>
          </SortableContext>
        </DndContext>
      </div>

      <ConfirmDialog
        open={Boolean(deleteTarget)}
        onOpenChange={(open) => {
          if (!open) {
            setDeleteTarget(null);
            setDeleteError(null);
          }
        }}
        title="Delete session?"
        description={
          deleteTarget ? `This will permanently delete “${deleteTarget.title}”.` : undefined
        }
        confirmLabel="Delete"
        cancelLabel="Cancel"
        confirmVariant="destructive"
        onConfirm={onConfirmDeleteSession}
      />
      {deleteError ? <p className="text-sm text-destructive">{deleteError}</p> : null}
    </div>
  );
}

"use client";

import { zodResolver } from "@hookform/resolvers/zod";
import Link from "next/link";
import { useParams, useRouter } from "next/navigation";
import { useRef, useState } from "react";
import { useForm } from "react-hook-form";
import { z } from "zod";
import { Button, buttonVariants } from "@/components/ui/Button";
import { apiFetch, applyServerFieldErrors, readApiErrorDetails } from "@/lib/api";
import {
  DASH_PAGE_MAX,
  dashBackLink,
  dashFormSection,
  dashInsetCard,
  dashInputCn,
  dashLabel,
  dashPageDescription,
  dashPageTitle,
  dashSectionCard,
  dashSelectCn
} from "@/lib/dashboardUi";
import { fileAcceptForMediaKind, type MediaKind } from "@/lib/mediaKind";
import { presignAndPutFile } from "@/lib/presignUpload";
import { cn } from "@/lib/utils";

const schema = z.object({
  title: z.string().min(1),
  durationSeconds: z.coerce.number().int().positive(),
  instructorName: z.string().min(1),
  tags: z.string().optional(),
  position: z.coerce.number().int().min(0).optional(),
  mediaKind: z.enum(["none", "audio", "video"]),
  mediaUrl: z.string().optional().nullable(),
  mediaType: z.string().optional().nullable()
});

type Form = z.infer<typeof schema>;

export default function NewSessionPage() {
  const params = useParams();
  const router = useRouter();
  const programId = typeof params.id === "string" ? params.id : "";
  const [error, setError] = useState<string | null>(null);
  const [uploadMsg, setUploadMsg] = useState<string | null>(null);
  const [uploading, setUploading] = useState(false);
  const fileRef = useRef<HTMLInputElement>(null);
  const form = useForm<Form>({
    resolver: zodResolver(schema),
    defaultValues: {
      title: "",
      durationSeconds: 600,
      instructorName: "",
      tags: "",
      mediaKind: "none",
      mediaUrl: "",
      mediaType: ""
    }
  });
  const mediaKind = form.watch("mediaKind") as MediaKind;

  async function onPickFile() {
    setUploadMsg(null);
    const file = fileRef.current?.files?.[0];
    if (!file) {
      return;
    }
    setUploading(true);
    try {
      const result = await presignAndPutFile(file);
      if (!result.ok) {
        setUploadMsg(result.message);
        return;
      }
      form.setValue("mediaUrl", result.publicUrl);
      form.setValue("mediaType", result.contentType);
      if (result.contentType.startsWith("audio/")) {
        form.setValue("mediaKind", "audio");
      } else if (result.contentType.startsWith("video/")) {
        form.setValue("mediaKind", "video");
      }
      setUploadMsg("Uploaded — URL will be saved when you create the session.");
    } finally {
      setUploading(false);
    }
  }

  async function onSubmit(data: Form) {
    setError(null);
    form.clearErrors();
    const pendingFile = fileRef.current?.files?.[0];
    if (pendingFile && !data.mediaUrl?.trim()) {
      setUploading(true);
      setUploadMsg(null);
      try {
        const uploadResult = await presignAndPutFile(pendingFile);
        if (!uploadResult.ok) {
          setError(uploadResult.message);
          setUploadMsg(uploadResult.message);
          return;
        }
        form.setValue("mediaUrl", uploadResult.publicUrl);
        form.setValue("mediaType", uploadResult.contentType);
        if (uploadResult.contentType.startsWith("audio/")) {
          form.setValue("mediaKind", "audio");
        } else if (uploadResult.contentType.startsWith("video/")) {
          form.setValue("mediaKind", "video");
        }
        data = {
          ...data,
          mediaUrl: uploadResult.publicUrl,
          mediaType: uploadResult.contentType,
          mediaKind: uploadResult.contentType.startsWith("video/")
            ? "video"
            : uploadResult.contentType.startsWith("audio/")
              ? "audio"
              : data.mediaKind
        };
        setUploadMsg("Uploaded — saving session.");
      } finally {
        setUploading(false);
      }
    }
    const tags =
      data.tags
        ?.split(/[|,]/)
        .map((t) => t.trim())
        .filter(Boolean) ?? [];
    const payload: Record<string, unknown> = {
      programId,
      title: data.title,
      durationSeconds: data.durationSeconds,
      instructorName: data.instructorName,
      tags
    };
    if (data.position !== undefined && !Number.isNaN(data.position)) {
      payload.position = data.position;
    }
    const mu = data.mediaUrl?.trim();
    if (mu) {
      payload.mediaUrl = mu;
      payload.mediaType = data.mediaType?.trim() || null;
    }
    const res = await apiFetch("/sessions", {
      method: "POST",
      body: JSON.stringify(payload)
    });
    const body = await res.json().catch(() => ({}));
    if (!res.ok) {
      form.clearErrors();
      const { message, details } = readApiErrorDetails(body);
      setError(message);
      if (details?.fieldErrors) {
        applyServerFieldErrors(form.setError, form.getValues(), details.fieldErrors);
      }
      return;
    }
    const created = body as { id?: string };
    if (created.id) {
      router.push(`/programs/${programId}/sessions/${created.id}/edit`);
    }
  }

  return (
    <div className={cn(DASH_PAGE_MAX, "space-y-8")}>
      <div>
        <Link href={`/programs/${programId}/sessions`} className={dashBackLink}>
          ← Back to sessions
        </Link>
        <h1 className={cn(dashPageTitle, "mt-6")}>New session</h1>
        <p className={dashPageDescription}>Add a session with optional media attachment.</p>
      </div>

      <div className={dashSectionCard}>
        <form onSubmit={form.handleSubmit(onSubmit)} className={dashFormSection}>
          <div className="space-y-2">
            <label className={dashLabel} htmlFor="sess-title">
              Title <span className="text-destructive">*</span>
            </label>
            <input id="sess-title" className={dashInputCn()} {...form.register("title")} />
          </div>
          <div className="space-y-2">
            <label className={dashLabel} htmlFor="sess-instructor">
              Instructor name <span className="text-destructive">*</span>
            </label>
            <input id="sess-instructor" className={dashInputCn()} {...form.register("instructorName")} />
          </div>
          <div className="grid gap-5 sm:grid-cols-2">
            <div className="space-y-2">
              <label className={dashLabel} htmlFor="sess-duration">
                Duration (seconds) <span className="text-destructive">*</span>
              </label>
              <input
                id="sess-duration"
                type="number"
                className={dashInputCn()}
                {...form.register("durationSeconds", { valueAsNumber: true })}
              />
            </div>
            <div className="space-y-2">
              <label className={dashLabel} htmlFor="sess-position">
                Position <span className="text-muted-foreground">(optional)</span>
              </label>
              <input id="sess-position" type="number" className={dashInputCn()} {...form.register("position")} />
            </div>
          </div>
          <div className="space-y-2">
            <label className={dashLabel} htmlFor="sess-tags">
              Tags <span className="text-muted-foreground">(comma separated)</span>
            </label>
            <input id="sess-tags" className={dashInputCn()} {...form.register("tags")} />
          </div>
          <div className="space-y-2">
            <label className={dashLabel} htmlFor="sess-media-kind">
              Media type
            </label>
            <select id="sess-media-kind" className={dashSelectCn} {...form.register("mediaKind")}>
              <option value="none">None</option>
              <option value="audio">Audio</option>
              <option value="video">Video</option>
            </select>
          </div>

          <div className={dashInsetCard}>
            <p className="text-sm font-medium text-foreground">Media file</p>
            <p className="mt-1 text-xs text-muted-foreground">
              Choose a file; use Upload to preview, or submit — create uploads if a file is still selected.
            </p>
            <input
              ref={fileRef}
              type="file"
              accept={fileAcceptForMediaKind(mediaKind)}
              className="mt-3 w-full max-w-full text-sm text-muted-foreground file:mr-3 file:rounded-lg file:border-0 file:bg-primary file:px-3 file:py-2 file:text-sm file:font-medium file:text-primary-foreground"
              disabled={uploading}
            />
            <div className="mt-4 flex flex-wrap gap-2">
              <Button type="button" variant="secondary" onClick={() => void onPickFile()} disabled={uploading}>
                {uploading ? "Uploading…" : "Upload"}
              </Button>
              {form.watch("mediaUrl") ? (
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  onClick={() => {
                    form.setValue("mediaUrl", "");
                    form.setValue("mediaType", "");
                    setUploadMsg(null);
                    if (fileRef.current) {
                      fileRef.current.value = "";
                    }
                  }}
                >
                  Clear media
                </Button>
              ) : null}
            </div>
            {form.watch("mediaUrl") ? (
              <p className="mt-3 break-all text-xs text-muted-foreground">{form.watch("mediaUrl")}</p>
            ) : null}
            {uploadMsg ? <p className="mt-2 text-xs text-muted-foreground">{uploadMsg}</p> : null}
          </div>

          {error ? <p className="text-sm text-destructive">{error}</p> : null}
          {Object.entries(form.formState.errors).map(([key, err]) =>
            err?.message ? (
              <p key={key} className="text-sm text-destructive">
                {err.message}
              </p>
            ) : null
          )}
          <div className="flex flex-wrap justify-end gap-2 border-t border-border pt-6">
            <Link href={`/programs/${programId}/sessions`} className={cn(buttonVariants({ variant: "outline" }))}>
              Cancel
            </Link>
            <Button type="submit" disabled={form.formState.isSubmitting || uploading}>
              {form.formState.isSubmitting ? "Creating…" : "Create session"}
            </Button>
          </div>
        </form>
      </div>
    </div>
  );
}

"use client";

import Link from "next/link";
import { useParams } from "next/navigation";
import { useEffect, useState } from "react";
import { ArrowRight } from "lucide-react";
import { buttonVariants } from "@/components/ui/Button";
import { apiFetch, readApiErrorMessage } from "@/lib/api";
import {
  DASH_PAGE_MAX,
  dashBackLink,
  dashInsetCard,
  dashPageDescription,
  dashPageTitle,
  dashPrimaryLink,
  dashSectionCard
} from "@/lib/dashboardUi";
import { formatSessionDuration } from "@/lib/formatDisplay";
import { cn } from "@/lib/utils";

type SessionDetail = {
  title?: string;
  durationSeconds?: number;
  instructorName?: string;
  tags?: string[];
  mediaUrl?: string | null;
  mediaType?: string | null;
};

export default function SessionDetailPage() {
  const params = useParams();
  const programId = typeof params.id === "string" ? params.id : "";
  const sessionId = typeof params.sessionId === "string" ? params.sessionId : "";
  const [state, setState] = useState<"loading" | "ready" | "error">("loading");
  const [error, setError] = useState<string | null>(null);
  const [session, setSession] = useState<SessionDetail | null>(null);

  useEffect(() => {
    if (!sessionId) {
      setError("Missing session id");
      setState("error");
      return;
    }
    let cancelled = false;
    setState("loading");
    setError(null);
    void (async () => {
      const res = await apiFetch(`/sessions/${sessionId}`);
      const body = await res.json().catch(() => ({}));
      if (cancelled) {
        return;
      }
      if (!res.ok) {
        setError(readApiErrorMessage(body, "Not found"));
        setState("error");
        return;
      }
      setSession(body as SessionDetail);
      setState("ready");
    })();
    return () => {
      cancelled = true;
    };
  }, [sessionId]);

  if (state === "loading") {
    return (
      <div className={cn(DASH_PAGE_MAX, "space-y-6")}>
        <div className={cn(dashSectionCard, "p-8")}>
          <p className="text-sm text-muted-foreground">Loading session…</p>
          <div className="mt-4 space-y-3">
            <div className="h-10 w-full animate-pulse rounded-lg bg-muted" />
            <div className="h-24 w-full animate-pulse rounded-lg bg-muted" />
          </div>
        </div>
      </div>
    );
  }

  if (state === "error" || !session) {
    return <p className="text-sm text-destructive">{error ?? "Failed to load session"}</p>;
  }

  const tags = session.tags?.length ? session.tags.join(", ") : "—";
  const mediaUrl = session.mediaUrl?.trim();

  return (
    <div className={cn(DASH_PAGE_MAX, "space-y-8")}>
      <div>
        <Link href={`/programs/${programId}/sessions`} className={dashBackLink}>
          ← Back to sessions
        </Link>
        <div className="mt-6 flex flex-wrap items-start justify-between gap-4">
          <div>
            <h1 className={dashPageTitle}>{session.title ?? "Session"}</h1>
            <p className={dashPageDescription}>Session details and media.</p>
          </div>
          <Link
            href={`/programs/${programId}/sessions/${sessionId}/edit`}
            className={cn(buttonVariants({ variant: "secondary", size: "sm" }), "shrink-0")}
          >
            Edit session
          </Link>
        </div>
      </div>

      <div className={dashSectionCard}>
        <dl className="divide-y divide-border px-6 py-2 text-sm">
          <div className="grid gap-1 py-4 sm:grid-cols-[140px_1fr] sm:gap-4">
            <dt className="text-xs font-medium uppercase tracking-[0.08em] text-muted-foreground">Instructor</dt>
            <dd className="font-medium text-foreground">{session.instructorName ?? "—"}</dd>
          </div>
          <div className="grid gap-1 py-4 sm:grid-cols-[140px_1fr] sm:gap-4">
            <dt className="text-xs font-medium uppercase tracking-[0.08em] text-muted-foreground">Duration</dt>
            <dd className="font-medium text-foreground">
              {typeof session.durationSeconds === "number"
                ? formatSessionDuration(session.durationSeconds)
                : "—"}
            </dd>
          </div>
          <div className="grid gap-1 py-4 sm:grid-cols-[140px_1fr] sm:gap-4">
            <dt className="text-xs font-medium uppercase tracking-[0.08em] text-muted-foreground">Tags</dt>
            <dd className="font-medium text-foreground">{tags}</dd>
          </div>
          <div className="grid gap-1 py-4 sm:grid-cols-[140px_1fr] sm:gap-4">
            <dt className="text-xs font-medium uppercase tracking-[0.08em] text-muted-foreground">Media</dt>
            <dd className="font-medium text-foreground">
              {mediaUrl ? (
                <>
                  <a href={mediaUrl} className={cn(dashPrimaryLink, "inline-flex flex-wrap items-center gap-1 break-all")} target="_blank" rel="noreferrer">
                    Open media
                    <ArrowRight className="size-3.5 shrink-0" aria-hidden />
                  </a>
                  {session.mediaType ? (
                    <span className="mt-1 block text-xs text-muted-foreground">{session.mediaType}</span>
                  ) : null}
                  <span className="mt-2 block max-w-xl break-all text-xs text-muted-foreground">{mediaUrl}</span>
                </>
              ) : (
                "None"
              )}
            </dd>
          </div>
        </dl>
      </div>

      <div className={dashInsetCard}>
        <Link href={`/programs/${programId}/sessions`} className={cn(buttonVariants({ variant: "outline" }))}>
          Back to sessions list
        </Link>
      </div>
    </div>
  );
}

"use client";

import { zodResolver } from "@hookform/resolvers/zod";
import Link from "next/link";
import { useParams, useRouter } from "next/navigation";
import { useEffect, useRef, useState } from "react";
import { useForm } from "react-hook-form";
import { z } from "zod";
import { Button, buttonVariants } from "@/components/ui/Button";
import { ConfirmDialog } from "@/components/ui/ConfirmDialog";
import { apiFetch, readApiErrorMessage, applyServerFieldErrors, readApiErrorDetails } from "@/lib/api";
import {
  DASH_PAGE_MAX,
  dashBackLink,
  dashFormSection,
  dashInsetCard,
  dashInputCn,
  dashLabel,
  dashPageDescription,
  dashPageTitle,
  dashPrimaryLink,
  dashSectionCard,
  dashSelectCn
} from "@/lib/dashboardUi";
import { fileAcceptForMediaKind, mimeToMediaKind, type MediaKind } from "@/lib/mediaKind";
import { presignAndPutFile } from "@/lib/presignUpload";
import { cn } from "@/lib/utils";

const schema = z.object({
  title: z.string().min(1),
  durationSeconds: z.coerce.number().int().positive(),
  instructorName: z.string().min(1),
  tags: z.string().optional(),
  mediaKind: z.enum(["none", "audio", "video"]),
  mediaUrl: z.string().optional().nullable(),
  mediaType: z.string().optional().nullable()
});

type Form = z.infer<typeof schema>;

function tagsFromString(s: string | undefined): string[] {
  return s?.split(/[|,]/).map((t) => t.trim()).filter(Boolean) ?? [];
}

export default function EditSessionPage() {
  const params = useParams();
  const router = useRouter();
  const programId = typeof params.id === "string" ? params.id : "";
  const sessionId = typeof params.sessionId === "string" ? params.sessionId : "";
  const [loadState, setLoadState] = useState<"loading" | "ready" | "error">("loading");
  const [loadError, setLoadError] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [uploadMsg, setUploadMsg] = useState<string | null>(null);
  const [uploading, setUploading] = useState(false);
  const [deleteOpen, setDeleteOpen] = useState(false);
  const [deleteError, setDeleteError] = useState<string | null>(null);
  const fileRef = useRef<HTMLInputElement>(null);
  const form = useForm<Form>({
    resolver: zodResolver(schema),
    defaultValues: {
      mediaKind: "none",
      mediaUrl: "",
      mediaType: ""
    }
  });
  const mediaKind = form.watch("mediaKind") as MediaKind;

  useEffect(() => {
    if (!sessionId) {
      setLoadError("Missing session id");
      setLoadState("error");
      return;
    }
    let cancelled = false;
    setLoadState("loading");
    setLoadError(null);
    void (async () => {
      const res = await apiFetch(`/sessions/${sessionId}`);
      const body = await res.json().catch(() => ({}));
      if (cancelled) {
        return;
      }
      if (!res.ok) {
        setLoadError(readApiErrorMessage(body, "Not found"));
        setLoadState("error");
        return;
      }
      const data = body as {
        title?: string;
        durationSeconds?: number;
        instructorName?: string;
        tags?: string[];
        mediaUrl?: string | null;
        mediaType?: string | null;
      };
      const mt = data.mediaType ?? "";
      form.reset({
        title: data.title ?? "",
        durationSeconds: data.durationSeconds ?? 0,
        instructorName: data.instructorName ?? "",
        tags: (data.tags ?? []).join(", "),
        mediaUrl: data.mediaUrl ?? "",
        mediaType: mt,
        mediaKind: mimeToMediaKind(mt || undefined)
      });
      setLoadState("ready");
    })();
    return () => {
      cancelled = true;
    };
  }, [sessionId, form]);

  async function onSubmit(data: Form) {
    setError(null);
    form.clearErrors();
    const pendingFile = fileRef.current?.files?.[0];
    if (pendingFile) {
      setUploading(true);
      setUploadMsg(null);
      try {
        const uploadResult = await presignAndPutFile(pendingFile);
        if (!uploadResult.ok) {
          setError(uploadResult.message);
          setUploadMsg(uploadResult.message);
          return;
        }
        const mediaUrl = uploadResult.publicUrl;
        const mediaType = uploadResult.contentType;
        form.setValue("mediaUrl", mediaUrl);
        form.setValue("mediaType", mediaType);
        if (mediaType.startsWith("audio/")) {
          form.setValue("mediaKind", "audio");
        } else if (mediaType.startsWith("video/")) {
          form.setValue("mediaKind", "video");
        }
        data = {
          ...data,
          mediaUrl,
          mediaType
        };
      } finally {
        setUploading(false);
      }
    }
    const res = await apiFetch(`/sessions/${sessionId}`, {
      method: "PATCH",
      body: JSON.stringify({
        title: data.title,
        durationSeconds: data.durationSeconds,
        instructorName: data.instructorName,
        tags: tagsFromString(data.tags),
        mediaUrl: data.mediaUrl?.trim() || null,
        mediaType: data.mediaUrl?.trim() ? data.mediaType?.trim() || null : null
      })
    });
    const resBody = await res.json().catch(() => ({}));
    if (!res.ok) {
      const { message, details } = readApiErrorDetails(resBody);
      setError(message);
      if (details?.fieldErrors) {
        applyServerFieldErrors(form.setError, form.getValues(), details.fieldErrors);
      }
      return;
    }
    router.push(`/programs/${programId}/sessions`);
  }

  async function onPickFile() {
    setUploadMsg(null);
    const file = fileRef.current?.files?.[0];
    if (!file) {
      return;
    }
    setUploading(true);
    try {
      const result = await presignAndPutFile(file);
      if (!result.ok) {
        setUploadMsg(result.message);
        return;
      }
      const mediaUrl = result.publicUrl;
      const mediaType = result.contentType;
      form.setValue("mediaUrl", mediaUrl);
      form.setValue("mediaType", mediaType);
      if (mediaType.startsWith("audio/")) {
        form.setValue("mediaKind", "audio");
      } else if (mediaType.startsWith("video/")) {
        form.setValue("mediaKind", "video");
      }

      const v = form.getValues();
      const patchRes = await apiFetch(`/sessions/${sessionId}`, {
        method: "PATCH",
        body: JSON.stringify({
          title: v.title,
          durationSeconds: v.durationSeconds,
          instructorName: v.instructorName,
          tags: tagsFromString(v.tags),
          mediaUrl,
          mediaType
        })
      });
      const patchBody = await patchRes.json().catch(() => ({}));
      if (!patchRes.ok) {
        form.clearErrors();
        const { message, details } = readApiErrorDetails(patchBody);
        if (details?.fieldErrors) {
          applyServerFieldErrors(form.setError, form.getValues(), details.fieldErrors);
        }
        setUploadMsg(message);
        return;
      }
      setUploadMsg("Upload complete — media saved.");
      router.refresh();
    } finally {
      setUploading(false);
    }
  }

  async function onConfirmDelete() {
    setDeleteError(null);
    const res = await apiFetch(`/sessions/${sessionId}`, { method: "DELETE" });
    if (!res.ok) {
      const body = await res.json().catch(() => ({}));
      setDeleteError(readApiErrorMessage(body, "Delete failed"));
      throw new Error("delete failed");
    }
    router.push(`/programs/${programId}/sessions`);
  }

  const mediaUrl = form.watch("mediaUrl")?.trim();

  if (loadState === "loading") {
    return (
      <div className={cn(DASH_PAGE_MAX, "space-y-6")}>
        <div className={cn(dashSectionCard, "p-8")}>
          <p className="text-sm text-muted-foreground">Loading session…</p>
          <div className="mt-4 space-y-3">
            <div className="h-10 w-full animate-pulse rounded-lg bg-muted" />
            <div className="h-24 w-full animate-pulse rounded-lg bg-muted" />
          </div>
        </div>
      </div>
    );
  }

  if (loadState === "error" || loadError) {
    return <p className="text-sm text-destructive">{loadError ?? "Failed to load session"}</p>;
  }

  return (
    <div className={cn(DASH_PAGE_MAX, "space-y-8")}>
      <div>
        <Link href={`/programs/${programId}/sessions`} className={dashBackLink}>
          ← Back to sessions
        </Link>
        <h1 className={cn(dashPageTitle, "mt-6")}>Edit session</h1>
        <p className={dashPageDescription}>Update metadata, URLs, or replace media.</p>
      </div>

      <div className={dashSectionCard}>
        <form onSubmit={form.handleSubmit(onSubmit)} className={dashFormSection}>
          <div className="space-y-2">
            <label className={dashLabel} htmlFor="es-title">
              Title <span className="text-destructive">*</span>
            </label>
            <input id="es-title" className={dashInputCn()} {...form.register("title")} />
          </div>
          <div className="space-y-2">
            <label className={dashLabel} htmlFor="es-instructor">
              Instructor name <span className="text-destructive">*</span>
            </label>
            <input id="es-instructor" className={dashInputCn()} {...form.register("instructorName")} />
          </div>
          <div className="space-y-2">
            <label className={dashLabel} htmlFor="es-duration">
              Duration (seconds) <span className="text-destructive">*</span>
            </label>
            <input
              id="es-duration"
              type="number"
              className={dashInputCn()}
              {...form.register("durationSeconds", { valueAsNumber: true })}
            />
          </div>
          <div className="space-y-2">
            <label className={dashLabel} htmlFor="es-tags">
              Tags <span className="text-muted-foreground">(comma separated)</span>
            </label>
            <input id="es-tags" className={dashInputCn()} {...form.register("tags")} />
          </div>
          <div className="space-y-2">
            <label className={dashLabel} htmlFor="es-media-kind">
              Media type
            </label>
            <select id="es-media-kind" className={dashSelectCn} {...form.register("mediaKind")}>
              <option value="none">None</option>
              <option value="audio">Audio</option>
              <option value="video">Video</option>
            </select>
          </div>

          {mediaUrl ? (
            <div className={dashInsetCard}>
              <p className="text-sm font-medium text-foreground">Current media</p>
              <a
                href={mediaUrl}
                className={cn(dashPrimaryLink, "mt-2 inline-flex break-all text-sm")}
                target="_blank"
                rel="noreferrer"
              >
                {mediaUrl}
              </a>
              <Button
                type="button"
                variant="outline"
                size="sm"
                className="mt-4"
                onClick={() => {
                  if (fileRef.current) {
                    fileRef.current.value = "";
                  }
                  fileRef.current?.click();
                }}
              >
                Replace file
              </Button>
            </div>
          ) : null}

          <div className={dashInsetCard}>
            <p className="text-sm font-medium text-foreground">
              {mediaUrl ? "Upload replacement" : "Media file"}
            </p>
            <p className="mt-1 text-xs text-muted-foreground">
              Choose a file and upload — or save the form after selecting to upload on submit.
            </p>
            <input
              ref={fileRef}
              type="file"
              accept={fileAcceptForMediaKind(mediaKind)}
              className="mt-3 w-full max-w-full text-sm text-muted-foreground"
              disabled={uploading}
            />
            <div className="mt-4 flex flex-wrap gap-2">
              <Button type="button" variant="secondary" onClick={() => void onPickFile()} disabled={uploading}>
                {uploading ? "Uploading…" : "Upload"}
              </Button>
            </div>
            {uploadMsg ? <p className="mt-2 text-xs text-muted-foreground">{uploadMsg}</p> : null}
          </div>

          <div className="space-y-2">
            <label className={dashLabel} htmlFor="es-media-url">
              Media URL <span className="text-muted-foreground">(optional)</span>
            </label>
            <input id="es-media-url" className={dashInputCn()} {...form.register("mediaUrl")} />
          </div>
          <div className="space-y-2">
            <label className={dashLabel} htmlFor="es-media-type">
              MIME type <span className="text-muted-foreground">(optional)</span>
            </label>
            <input id="es-media-type" className={dashInputCn()} {...form.register("mediaType")} />
          </div>

          {error ? <p className="text-sm text-destructive">{error}</p> : null}
          {Object.entries(form.formState.errors).map(([key, err]) =>
            err?.message ? (
              <p key={key} className="text-sm text-destructive">
                {err.message}
              </p>
            ) : null
          )}
          <div className="flex flex-wrap justify-end gap-2 border-t border-border pt-6">
            <Link href={`/programs/${programId}/sessions`} className={cn(buttonVariants({ variant: "outline" }))}>
              Cancel
            </Link>
            <Button type="submit" disabled={form.formState.isSubmitting || uploading}>
              {form.formState.isSubmitting ? "Saving…" : "Save changes"}
            </Button>
            <Button type="button" variant="destructive" onClick={() => setDeleteOpen(true)}>
              Delete session
            </Button>
          </div>
        </form>
      </div>

      <ConfirmDialog
        open={deleteOpen}
        onOpenChange={setDeleteOpen}
        title="Delete session?"
        description="This cannot be undone."
        confirmLabel="Delete"
        cancelLabel="Cancel"
        confirmVariant="destructive"
        onConfirm={onConfirmDelete}
      />
      {deleteError ? <p className="text-sm text-destructive">{deleteError}</p> : null}
    </div>
  );
}

